import { useState, useRef, useEffect, useCallback } from "react";

/* ─── Easing — one curve, one clock ─── */
const DUI_T = "0.55s";
const DUI_CURVE = "cubic-bezier(0.4, 0, 0.15, 1)";
const DUI_E = `${DUI_T} ${DUI_CURVE}`;
const DUI_SPRING = "cubic-bezier(0.22, 1.2, 0.36, 1)";
const DUI_E_SPRING = `0.52s ${DUI_SPRING}`;

/* ─── Images ─── */
const PLANE_IMG = "data:image/webp;base64,";
const CAR_IMG = "data:image/webp;base64,";


/* ─── Images ─── */


/* ─── Shimmer text style ─── */
const shimmer = {
  fontFamily: "'Inter', sans-serif",
  fontSize: 18, fontWeight: 500, letterSpacing: "-0.01em",
  background: "linear-gradient(90deg, #333 0%, #333 38%, #a8c0d4 50%, #333 62%, #333 100%)",
  backgroundSize: "300% 100%",
  WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
  backgroundClip: "text", animation: "shimmerSlide 8s ease-in-out infinite",
};

/* ─── Asset components ─── */

const PlaneIcon = ({ style }) => (
  <img src={PLANE_IMG} alt="" style={{ width: 149, height: 52, objectFit: "contain", ...style }} />
)

const CarIcon = ({ style }) => (
  <img src={CAR_IMG} alt=""
    style={{ width: 152, height: 64, objectFit: "contain", ...style }} />
);


const DELTA_IMG = "data:image/webp;base64,";

const DeltaLogo = () => (
  <img src={DELTA_IMG} alt="Delta" style={{ height: 14, objectFit: "contain" }} />
)

const UBER_IMG = "data:image/webp;base64,";
const FLIGHT_MAP = "data:image/webp;base64,";
const TRANSFER_MAP = "data:image/jpeg;base64,";

const UberBadge = ({ style }) => (
  <div style={{
    background: "#111", borderRadius: 10, width: 44, height: 44,
    display: "flex", alignItems: "center", justifyContent: "center", ...style,
  }}>
    <img src={UBER_IMG} alt="Uber" style={{ width: 28, objectFit: "contain" }} />
  </div>
)


/* ─── Route overlay ─── */
const FlightRoute = ({ visible }) => (
  <svg viewBox="0 0 729 320" preserveAspectRatio="xMidYMax slice" style={{
    position: "absolute", top: 0, left: 0, width: "100%", height: "100%", zIndex: 3,
    opacity: visible ? 1 : 0,
    transform: visible ? "translateY(0)" : "translateY(-25%)",
    transition: visible
      ? `opacity 0.15s ease 0.08s, transform 0.4s ${DUI_SPRING}`
      : `opacity 0.08s ease, transform 0.3s ${DUI_CURVE}`,
    pointerEvents: "none",
  }}>
    <path d="M 145 235 C 300 60, 500 60, 640 160" fill="none" stroke="#222"
      strokeWidth="1.5" strokeDasharray="8 6" strokeLinecap="round"
      style={{ animation: "lineShimmer 12s linear infinite, routeShimmer 4s ease-in-out infinite" }} />
    <circle cx="145" cy="235" r="11" fill="rgba(0,0,0,0.12)" />
    <circle cx="145" cy="235" r="6" fill="#111" />
    <circle cx="640" cy="160" r="11" fill="rgba(0,0,0,0.12)" />
    <circle cx="640" cy="160" r="6" fill="#111" />
  </svg>
);

/* ═══════════════════════════════════════════
   MAIN COMPONENT
   ═══════════════════════════════════════════ */
function DynamicUIExperiment() {
  const [mode, setMode] = useState("flight");
  const cardRef = useRef(null);
  const modeRef = useRef(mode);
  const snapRef = useRef(null);
  modeRef.current = mode;
  const f = mode === "flight";

  const toggle = (m) => {
    if (m === modeRef.current) return;
    const el = cardRef.current;
    if (!el) { setMode(m); return; }

    // One fluid spring — no hard phases
    el.style.transition = `width ${DUI_E_SPRING}, height ${DUI_E_SPRING}, transform 0.52s ${DUI_SPRING}`;
    el.style.transform = "scaleX(1) scaleY(1)";
    setMode(m);
  };

  useEffect(() => {
    const onKey = (e) => {
      if (e.key === "ArrowRight" && modeRef.current === "flight") {
        if (snapRef.current) snapRef.current(modeRef.current === "flight" ? 128 : 150, false);
        toggle("transfer");
      } else if (e.key === "ArrowLeft" && modeRef.current === "transfer") {
        if (snapRef.current) snapRef.current(modeRef.current === "transfer" ? 8 : 13, false);
        toggle("flight");
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  return (
    <div style={{
      width: "100%", height: "100%", background: "#dde1e8",
      display: "flex", alignItems: "center", justifyContent: "center",
      overflow: "hidden", fontFamily: "'Inter', -apple-system, sans-serif", userSelect: "none",
      paddingBottom: 200,
    }}>
      <style>{`
        @keyframes shimmerSlide { 0%{background-position:200% 50%} 100%{background-position:-200% 50%} }
        @keyframes lineShimmer { 0%{stroke-dashoffset:0} 100%{stroke-dashoffset:56} }
        @keyframes routeShimmer { 0%{opacity:0.4} 50%{opacity:0.8} 100%{opacity:0.4} }
      `}</style>

      {/* ── Card (scaled 75%) ── */}
      <div style={{ transform: "scale(0.75)", transformOrigin: "50% 50%" }}>
      <div ref={cardRef} style={{
        width: f ? 720 : 480, height: f ? 488 : 575,
        background: "#fff", borderRadius: 28, overflow: "hidden",
        boxShadow: "0 30px 100px rgba(0,0,0,0.05), 0 60px 160px rgba(0,0,0,0.04), 0 100px 200px rgba(0,0,0,0.03)",
        display: "flex", flexDirection: "column",
        transition: `width ${DUI_E_SPRING}, height ${DUI_E_SPRING}`,
        transformOrigin: "50% 50%",
        willChange: "width, height, transform",
      }}>

        {/* ── Flight info (top) ── */}
        <div style={{
          display: "grid", gridTemplateRows: f ? "1fr" : "0fr",
          transition: `grid-template-rows ${DUI_E_SPRING}`,
        }}>
          <div style={{ overflow: "hidden" }}>
            <div style={{
              padding: "20px 28px 16px",
              opacity: f ? 1 : 0,
              transform: f ? "translateY(0)" : "translateY(10px)",
              transition: f ? `opacity 0.4s ease 0.15s, transform ${DUI_E_SPRING}` : `opacity 0.15s ease, transform ${DUI_E_SPRING}`,
            }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                    <path d="M18.3333 13.3332V11.6665L11.25 7.49984V2.9165C11.25 2.22484 10.6916 1.6665 9.99996 1.6665C9.30829 1.6665 8.74996 2.22484 8.74996 2.9165V7.49984L1.66663 11.6665V13.3332L8.74996 11.2498V15.8332L6.66663 17.0832V18.3332L9.99996 17.4998L13.3333 18.3332V17.0832L11.25 15.8332V11.2498L18.3333 13.3332Z" fill="#15171A"/>
                  </svg>
                  <span style={shimmer}>Booking Flight</span>
                </div>
                <DeltaLogo />
              </div>
              <div style={{ display: "flex", alignItems: "center" }}>
                <div style={{ display: "flex", alignItems: "center", flex: 1 }}>
                  <div>
                    <div style={{ fontSize: 13, color: "#999", fontWeight: 500, marginBottom: 10 }}>New York</div>
                    <div style={{ fontSize: 42, fontWeight: 500, color: "#111", letterSpacing: "-0.04em", lineHeight: 1 }}>JFK</div>
                    <div style={{ fontSize: 13, color: "#aaa", marginTop: 6 }}>April 6, 11:00 am</div>
                  </div>
                  <div style={{ margin: "0 20px", display: "flex", alignItems: "center", gap: 4, padding: "0 10px" }}>
                    <div style={{ width: 50, height: 0, borderTop: "1.5px dashed #ccc" }} />
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                      <path d="M10 6L8.59 7.41L13.17 12L8.59 16.59L10 18L16 12L10 6Z" fill="black"/>
                    </svg>
                    <div style={{ width: 50, height: 0, borderTop: "1.5px dashed #ccc" }} />
                  </div>
                  <div>
                    <div style={{ fontSize: 13, color: "#999", fontWeight: 500, marginBottom: 10 }}>San Francisco</div>
                    <div style={{ fontSize: 42, fontWeight: 500, color: "#111", letterSpacing: "-0.04em", lineHeight: 1 }}>SFO</div>
                    <div style={{ fontSize: 13, color: "#aaa", marginTop: 6 }}>April 6, 1:34 pm</div>
                  </div>
                </div>
                <div style={{ flexShrink: 0, position: "relative", marginTop: -12 }}>
                  <PlaneIcon style={{ position: "absolute", top: 14, left: 6, filter: "blur(8px) opacity(0.15)" }} />
                  <PlaneIcon style={{ position: "relative" }} />
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* ── Map (middle) ── */}
        <div style={{ padding: f ? "0 16px 16px" : "16px 16px 0", transition: `padding ${DUI_E}`, flex: 1, minHeight: 0 }}>
          <div style={{
            width: "100%", height: "100%", borderRadius: 22, background: "#F3F3F3",
            position: "relative", overflow: "hidden",
          }}>
            {/* Flight map */}
            <img src={FLIGHT_MAP} alt="" style={{
              position: "absolute", inset: 0, width: "100%", height: "100%",
              objectFit: "cover",
              opacity: f ? 1 : 0,
              transform: f ? "scale(1)" : "scale(1.15)",
              transformOrigin: "50% 50%",
              zIndex: f ? 2 : 1,
              transition: f
                ? `opacity 0.01s ease, transform ${DUI_E_SPRING}`
                : `opacity 0.35s ease, transform ${DUI_E_SPRING}`,
            }} />
            <FlightRoute visible={f} />

            {/* Transfer map */}
            <div style={{
              position: "absolute", inset: 0, width: "100%", height: "100%",
              opacity: f ? 0 : 1,
              transform: f ? "scale(1.15)" : "scale(1)",
              transformOrigin: "50% 50%",
              zIndex: f ? 1 : 2,
              transition: f
                ? `opacity 0.35s ease, transform ${DUI_E_SPRING}`
                : `opacity 0.01s ease, transform ${DUI_E_SPRING}`,
            }}>
              <img src={TRANSFER_MAP} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            </div>

            {/* Transfer route overlay */}
            <svg viewBox="0 0 500 500" preserveAspectRatio="xMidYMid slice" style={{
              position: "absolute", top: 0, left: 0, width: "100%", height: "100%", zIndex: 3,
              opacity: f ? 0 : 1,
              transition: f
                ? `opacity 0.08s ease`
                : `opacity 0.3s ease 0.15s`,
              pointerEvents: "none",
            }}>
              <defs>
                <linearGradient id="transferShimmer" gradientUnits="userSpaceOnUse" x1="360" y1="320" x2="90" y2="300">
                  <stop offset="0%" stopColor="#222" />
                  <stop offset="38%" stopColor="#222" />
                  <stop offset="50%" stopColor="#a8c0d4" />
                  <stop offset="62%" stopColor="#222" />
                  <stop offset="100%" stopColor="#222" />
                  <animate attributeName="x1" values="560;-100" dur="4s" repeatCount="indefinite" />
                  <animate attributeName="x2" values="160;-500" dur="4s" repeatCount="indefinite" />
                </linearGradient>
              </defs>
              <path d="M 90 300 A 150 150 0 0 1 350 315" fill="none" stroke="url(#transferShimmer)"
                strokeWidth="1.5" strokeLinecap="round" />
              <circle cx="90" cy="300" r="11" fill="rgba(0,0,0,0.12)" />
              <circle cx="90" cy="300" r="6" fill="#111" />
              <circle cx="350" cy="315" r="11" fill="rgba(0,0,0,0.12)" />
              <circle cx="350" cy="315" r="6" fill="#111" />
            </svg>

            {/* Uber badge */}
            <UberBadge style={{
              position: "absolute", top: 16, right: 16, zIndex: 10,
              opacity: f ? 0 : 1,
              transform: f ? "scale(0.85)" : "scale(1)",
              transition: f ? `opacity 0.15s ease, transform 0.15s ease` : `opacity 0.3s ease 0.25s, transform 0.3s ease 0.25s`,
            }} />
          </div>
        </div>

        {/* ── Transfer info (bottom) ── */}
        <div style={{
          display: "grid", gridTemplateRows: f ? "0fr" : "1fr",
          transition: `grid-template-rows ${DUI_E_SPRING}`,
        }}>
          <div style={{ overflow: "hidden" }}>
            <div style={{
              padding: "20px 28px 28px",
              opacity: f ? 0 : 1,
              transform: f ? "translateY(-10px)" : "translateY(0)",
              transition: f ? `opacity 0.15s ease, transform ${DUI_E_SPRING}` : `opacity 0.4s ease 0.15s, transform ${DUI_E_SPRING}`,
            }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                <span style={shimmer}>Booking Transfer</span>
                <div style={{
                  background: "rgba(180,160,220,0.15)",
                  borderRadius: 6, padding: "6px 14px",
                  fontSize: 13, fontWeight: 500,
                  backgroundClip: "padding-box",
                }}>
                  <span style={{
                    background: "linear-gradient(90deg, #7a5caa 0%, #7a5caa 38%, #b49cd4 50%, #7a5caa 62%, #7a5caa 100%)",
                    backgroundSize: "300% 100%",
                    WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                    backgroundClip: "text",
                    animation: "shimmerSlide 6s ease-in-out infinite",
                  }}>Preference Applied</span>
                </div>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
                <div>
                  <div style={{ fontSize: 28, fontWeight: 500, color: "#111", letterSpacing: "-0.03em", marginBottom: 6 }}>Uber Black</div>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <span style={{ fontSize: 15, color: "#999" }}>Terminal 2</span>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                      <path d="M5 12h14M13 6l6 6-6 6" stroke="#999" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                    <span style={{ fontSize: 15, color: "#999" }}>Home</span>
                  </div>
                </div>
                <div style={{ position: "relative" }}>
                  <CarIcon style={{ position: "absolute", top: 6, left: 3, filter: "blur(10px) opacity(0.06)" }} />
                  <CarIcon style={{ position: "relative" }} />
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      </div>

      {/* ── Elastic Toggle Switch ── */}
      {(() => {
        const containerW = typeof window !== "undefined" ? window.innerWidth : 1200;
        const isScaled = containerW < 800;
        const PILL_W = isScaled ? 210 : 120;
        const PAD = isScaled ? 14 : 8;
        const PILL_H = isScaled ? 80 : 48;
        const TRACK_W = PILL_W * 2 + PAD * 2;
        const L = PAD;
        const R = PAD + PILL_W;
        const MID = L + PILL_W / 2;

        const state = useRef({ active: false, sx: 0, sl: 0, lx: 0, vx: 0 });
        const pillRef = useRef(null);
        const trackRef = useRef(null);

        const onDown = useCallback((e) => {
          e.preventDefault();
          const p = pillRef.current, t = trackRef.current;
          if (!p || !t) return;
          p.style.transition = "none";
          t.style.transition = "none";
          state.current = { active: true, sx: e.clientX, sl: parseFloat(p.style.left) || (f ? L : R), lx: e.clientX, vx: 0, moved: false };
          e.currentTarget.setPointerCapture(e.pointerId);
        }, [f]);

        const onMove = useCallback((e) => {
          const s = state.current;
          if (!s.active) return;
          const p = pillRef.current, t = trackRef.current;
          if (!p || !t) return;

          if (Math.abs(e.clientX - s.sx) > 3) s.moved = true;
          if (!s.moved) return;

          let raw = s.sl + (e.clientX - s.sx);
          // Tight rubber band — only 15% past edges, hard clamp at ±20px overdrag
          if (raw < L) raw = L + Math.max(-20, (raw - L)) * 0.15;
          if (raw > R) raw = R + Math.min(20, (raw - R)) * 0.15;

          s.vx = e.clientX - s.lx;
          s.lx = e.clientX;
          // Clamp velocity
          const v = Math.max(-8, Math.min(8, s.vx));

          p.style.left = raw + "px";

          // Pill squish — clamped
          const sx = 1 + Math.min(0.06, Math.abs(v) * 0.008);
          const sy = 1 / sx;
          const skew = Math.max(-6, Math.min(6, -v * 1.2));
          p.style.transform = `skewX(${skew}deg) scaleX(${sx}) scaleY(${sy})`;

          // Track deformation — very subtle, all clamped
          const tSkew = Math.max(-2.5, Math.min(2.5, skew * 0.35));
          const tSx = 1 + Math.min(0.015, Math.abs(v) * 0.002);
          const tSy = 2 - tSx;
          const shift = Math.max(-3, Math.min(3, (((raw - L) / PILL_W) * 2 - 1) * 3));
          t.style.transform = `translateX(${shift}px) skewX(${tSkew}deg) scaleX(${tSx}) scaleY(${tSy})`;
        }, []);

        const snap = useCallback((dest, fromDrag) => {
          const p = pillRef.current, t = trackRef.current;
          if (!p || !t) return;
          const dir = dest === R ? 1 : -1;

          if (fromDrag) {
            // DRAG RELEASE: spring both back with the elastic feel you loved
            const spring = "0.5s cubic-bezier(0.175, 0.885, 0.32, 1.2)";
            p.style.transition = `left 0.4s cubic-bezier(0.4, 0, 0.2, 1), transform ${spring}`;
            t.style.transition = `transform ${spring}`;
            p.style.left = dest + "px";
            p.style.transform = "skewX(0deg) scaleX(1) scaleY(1)";
            t.style.transform = "none";
          } else {
            // CLICK: 4-phase fluid physics

            // Phase 1: Pill stretches in travel direction (track stays still)
            p.style.transition = "none";
            t.style.transition = "none";
            p.style.transform = `skewX(${dir * -5}deg) scaleX(1.1) scaleY(0.92)`;
            // Track: nothing yet

            requestAnimationFrame(() => {
              // Phase 2: Slide to destination, pill stays stretched, track starts to follow
              p.style.transition = "left 0.32s cubic-bezier(0.4, 0, 0.2, 1), transform 0.32s cubic-bezier(0.4, 0, 0.2, 1)";
              t.style.transition = "transform 0.32s cubic-bezier(0.4, 0, 0.2, 1)";
              p.style.left = dest + "px";
              p.style.transform = `skewX(${dir * 2}deg) scaleX(0.95) scaleY(1.05)`;
              t.style.transform = `translateX(${dir * 2}px) skewX(${dir * 1}deg) scaleX(0.99) scaleY(1.01)`;

              const onEnd = (e) => {
                if (e.propertyName !== "left") return;
                p.removeEventListener("transitionend", onEnd);
                // Phase 3: Impact — both squish into the wall
                p.style.transition = "none";
                t.style.transition = "none";
                p.style.transform = `skewX(${dir * 6}deg) scaleX(0.88) scaleY(1.12)`;
                t.style.transform = `translateX(${dir * 3}px) skewX(${dir * 2.5}deg) scaleX(0.98) scaleY(1.02)`;
                // Phase 4: Spring back
                requestAnimationFrame(() => {
                  const spring = "0.55s cubic-bezier(0.175, 0.885, 0.32, 1.25)";
                  p.style.transition = `transform ${spring}`;
                  t.style.transition = `transform ${spring}`;
                  p.style.transform = "skewX(0deg) scaleX(1) scaleY(1)";
                  t.style.transform = "none";
                });
              };
              p.addEventListener("transitionend", onEnd);
            });
          }
        }, []);
        snapRef.current = snap;

        const onUp = useCallback((e) => {
          const s = state.current;
          if (!s.active) return;
          s.active = false;

          if (!s.moved) {
            // It was a click/tap, not a drag — figure out which side
            const track = trackRef.current;
            if (!track) return;
            const rect = track.getBoundingClientRect();
            const scale = rect.width / (TRACK_W);
            const clickX = ((e.clientX || s.sx) - rect.left) / scale;
            const goRight = clickX > TRACK_W / 2;
            const dest = goRight ? R : L;
            const targetMode = goRight ? "transfer" : "flight";
            if (targetMode !== mode) {
              snap(dest, false);
              toggle(targetMode);
            }
            return;
          }

          // It was a drag
          const cur = parseFloat(pillRef.current?.style.left ?? MID);
          const goRight = (cur + s.vx * 5) > MID;
          const dest = goRight ? R : L;

          snap(dest, true);
          if (goRight) toggle("transfer"); else toggle("flight");
        }, [snap, mode]);


        return (
          <div ref={trackRef}
            onPointerDown={onDown} onPointerMove={onMove} onPointerUp={onUp}
            style={{
            position: "absolute", bottom: 136, left: "50%", marginLeft: -(TRACK_W / 2),
            width: TRACK_W, height: PILL_H + PAD * 2, borderRadius: 1000,
            background: "rgba(255,255,255,0.45)",
            backdropFilter: "blur(16px)", WebkitBackdropFilter: "blur(16px)",
            border: "1px solid rgba(255,255,255,0.6)",
            boxShadow: "0 2px 12px rgba(0,0,0,0.04), inset 0 1px 0 rgba(255,255,255,0.5)",
            userSelect: "none", touchAction: "none", cursor: "grab",
            transformOrigin: "50% 50%",
            willChange: "transform",
          }}>
            <div ref={(el) => {
                pillRef.current = el;
                if (el && !state.current.active && el.style.left === "") {
                  el.style.left = (f ? L : R) + "px";
                }
              }}
              style={{
                position: "absolute", top: PAD,
                width: PILL_W, height: PILL_H, borderRadius: 1000,
                background: "rgba(255,255,255,0.85)",
                boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
                transition: "left 0.4s cubic-bezier(0.4, 0, 0.2, 1), transform 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.1)",
                transformOrigin: "50% 50%", zIndex: 1, willChange: "left, transform",
                pointerEvents: "none",
              }}
            />
            {["flight", "transfer"].map((m, i) => (
              <div key={m} style={{
                position: "absolute", top: PAD, left: PAD + i * PILL_W,
                width: PILL_W, height: PILL_H, borderRadius: 1000,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: isScaled ? 26 : 16, fontWeight: 500, fontFamily: "'Inter', sans-serif",
                color: mode === m ? "#111" : "#999",
                zIndex: 2, textTransform: "capitalize",
                transition: "color 0.3s ease",
                pointerEvents: "none",
              }}>{m}</div>
            ))}
          </div>
        );
      })()}
    </div>
  );
}

export default DynamicUIExperiment;
